record.field:
{
    "type": "object",
    "properties": {
        "campaign_name": {"type": "string", "description": "Name of a specific campaign to look up, optional"}
    },
    "required": []
}

{
    "type": "object",
    "properties": {
        "campaign_name": {"type": "string", "description": "Name of the campaign"},
        "send_email": {"type": "boolean", "description": "Whether to send emails (default true)"},
        "send_sms": {"type": "boolean", "description": "Whether to send SMS (default false)"}
    },
    "required": ["campaign_name"]
}

{
    "type": "object",
    "properties": {
        "message": {"type": "string", "description": "The post message text"},
        "scheduled_date": {"type": "string", "format": "date-time", "description": "When to publish (ISO 8601)"},
        "platform": {"type": "string", "enum": ["facebook", "instagram"], "description": "Platform to post to"}
    },
    "required": ["message", "scheduled_date"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Campaign name"},
        "subject": {"type": "string", "description": "Email subject line"},
        "schedule_type": {"type": "string", "enum": ["one_time", "recurring"], "description": "One-time or recurring campaign"},
        "scheduled_date": {"type": "string", "format": "date", "description": "When to send (YYYY-MM-DD)"},
        "send_email": {"type": "boolean", "description": "Send via email", "default": true},
        "send_sms": {"type": "boolean", "description": "Send via SMS", "default": false}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "message": {"type": "string", "description": "Post message text"},
        "platform": {"type": "string", "enum": ["facebook", "instagram", "both"], "description": "Platform to post on"},
        "scheduled_date": {"type": "string", "format": "date-time", "description": "When to post (optional - draft if not specified)"}
    },
    "required": ["message"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Card name/title"},
        "card_type": {"type": "string", "description": "Type of card"},
        "subtitle": {"type": "string", "description": "Card subtitle"},
        "body": {"type": "string", "description": "Card body content"},
        "publish_kiosk": {"type": "boolean", "description": "Show on kiosk", "default": true},
        "publish_portal": {"type": "boolean", "description": "Show on member portal", "default": false}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "title": {"type": "string", "description": "Announcement title"},
        "body": {"type": "string", "description": "Announcement content"},
        "active": {"type": "boolean", "description": "Whether announcement is active", "default": true}
    },
    "required": ["title", "body"]
}
